#!/usr/bin/env bash
# ==============================================================================
#  StreamForge — IPTV Manager with EPG Support
#  Single-file Proxmox LXC Helper Script
#  https://github.com/rpoltera/streamforge
#
#  Run this on your Proxmox VE host:
#    bash -c "$(curl -fsSL https://raw.githubusercontent.com/rpoltera/streamforge/refs/heads/main/streamforge.sh)"
# ==============================================================================

set -Eeuo pipefail
trap 'echo -e "\n\033[01;31m[ERROR]\033[m on line ${LINENO}: ${BASH_COMMAND}" >&2; exit 1' ERR

# ── Colours ───────────────────────────────────────────────────────────────────
YW='\033[33m'; GN='\033[1;92m'; RD='\033[01;31m'
BL='\033[36m'; DGN='\033[32m'; CL='\033[m'
BFR="\\r\\033[K"
CM="${GN}✓${CL}"; CROSS="${RD}✗${CL}"; TAB="  "
msg_info()  { echo -ne "${TAB}${YW}[ .. ]${CL} ${1}..."; }
msg_ok()    { echo -e  "${BFR}${TAB}${CM} ${1}"; }
msg_error() { echo -e  "${BFR}${TAB}${CROSS} ${1}"; exit 1; }

# ── LXC defaults ──────────────────────────────────────────────────────────────
APP="StreamForge"; NSAPP="streamforge"
CT_CPU="2"; CT_RAM="1024"; CT_DISK="4"; CT_TAGS="iptv;media;epg"
NEXTID=$(pvesh get /cluster/nextid 2>/dev/null || echo "100")

# ── Banner ────────────────────────────────────────────────────────────────────
header_info() {
  clear
  echo -e '\033[36m'
  cat << 'BANNER'
   _____ __                             ______
  / ___// /_________  ____ _____ ___  / ____/___  _________ ____
  \__ \/ __/ ___/ _ \/ __ `/ __ `__ \/ /_  / __ \/ ___/ __ `/ _ \
 ___/ / /_/ /  /  __/ /_/ / / / / / / __/ / /_/ / /  / /_/ /  __/
/____/\__/_/   \___/\__,_/_/ /_/ /_/_/    \____/_/   \__, /\___/
                                                     /____/
BANNER
  echo -e '\033[m'
  echo -e "  \033[36mIPTV Channel Manager with EPG / XMLTV Support\033[m"
  echo -e "  \033[32mgithub.com/rpoltera/streamforge\033[m\n"
}

# ── Settings prompt ───────────────────────────────────────────────────────────
prompt_settings() {
  echo -e "${YW}Default container settings:${CL}"
  echo -e "  CT ID   : ${BL}${NEXTID}${CL}    Hostname: ${BL}${NSAPP}${CL}"
  echo -e "  CPU     : ${BL}${CT_CPU} cores${CL}  RAM: ${BL}${CT_RAM} MB${CL}  Disk: ${BL}${CT_DISK} GB${CL}"
  echo -e "  OS      : ${BL}Debian 12${CL}  Network: ${BL}DHCP on vmbr0${CL}  Type: ${BL}Unprivileged${CL}\n"
  read -r -p "Use default settings? [Y/n]: " yn
  case "${yn,,}" in
    n|no) advanced_settings ;;
    *)    CT_ID=$NEXTID; CT_HN=$NSAPP; CT_BRG="vmbr0"; CT_NET="dhcp"; CT_GATE=""; CT_VLAN="" ;;
  esac
}

advanced_settings() {
  echo -e "\n${BL}Advanced Settings${CL}\n"
  read -r -p "  CT ID          [${NEXTID}]: " i; CT_ID=${i:-$NEXTID}
  read -r -p "  Hostname       [${NSAPP}]: "  i; CT_HN=${i:-$NSAPP}
  read -r -p "  CPU cores      [${CT_CPU}]: " i; CT_CPU=${i:-$CT_CPU}
  read -r -p "  RAM MB         [${CT_RAM}]: " i; CT_RAM=${i:-$CT_RAM}
  read -r -p "  Disk GB        [${CT_DISK}]: " i; CT_DISK=${i:-$CT_DISK}
  read -r -p "  Bridge         [vmbr0]: "     i; CT_BRG=${i:-vmbr0}
  read -r -p "  IP (blank=DHCP): "            i; CT_NET=${i:-dhcp}
  CT_GATE=""
  [[ "$CT_NET" != "dhcp" ]] && { read -r -p "  Gateway: " i; CT_GATE=${i:-""}; }
  read -r -p "  VLAN tag (blank=none): "      i; CT_VLAN=${i:-""}
}

# ── Check for existing StreamForge container ──────────────────────────────────
check_existing() {
  if pct list 2>/dev/null | grep -qi "$NSAPP"; then
    echo -e "\n${YW}Existing StreamForge container detected.${CL}"
    read -r -p "Update it instead of creating new? [y/N]: " upd
    if [[ "${upd,,}" == "y" ]]; then
      local CTID
      CTID=$(pct list 2>/dev/null | grep -i "$NSAPP" | awk '{print $1}' | head -1)
      echo -e "\n${YW}Updating CT${CTID}...${CL}\n"
      CT_ID=$CTID
      install_app_in_container --update
      echo -e "\n${GN}Update complete!${CL}\n"; exit 0
    fi
  fi
}

# ── Get Debian 12 template ────────────────────────────────────────────────────
get_template() {
  msg_info "Locating template storage"
  TMPL_STOR=$(pvesm status -content vztmpl 2>/dev/null | awk 'NR>1{print $1;exit}')
  [[ -z "$TMPL_STOR" ]] && TMPL_STOR="local"
  msg_ok "Template storage: ${TMPL_STOR}"

  msg_info "Checking for Debian 12 template"
  TEMPLATE=$(pveam list "$TMPL_STOR" 2>/dev/null | grep "debian-12" | sort -V | tail -1 | awk '{print $1}')
  if [[ -z "$TEMPLATE" ]]; then
    msg_info "Downloading Debian 12 template"
    pveam update >/dev/null 2>&1
    local DL
    DL=$(pveam available --section system 2>/dev/null | grep "debian-12" | sort -V | tail -1 | awk '{print $1}')
    [[ -z "$DL" ]] && msg_error "No Debian 12 template found."
    pveam download "$TMPL_STOR" "$DL" >/dev/null 2>&1
    TEMPLATE="${TMPL_STOR}:vztmpl/${DL}"
  fi
  msg_ok "Template: ${TEMPLATE}"
}

# ── Create LXC container ──────────────────────────────────────────────────────
create_container() {
  msg_info "Locating container storage"
  local ROOTFS
  ROOTFS=$(pvesm status -content images 2>/dev/null | awk 'NR>1{print $1;exit}')
  [[ -z "$ROOTFS" ]] && ROOTFS="local-lvm"
  msg_ok "Container storage: ${ROOTFS}"

  local NET_STR="name=eth0,bridge=${CT_BRG},ip=${CT_NET}"
  [[ -n "${CT_GATE:-}" ]] && NET_STR+=",gw=${CT_GATE}"
  [[ -n "${CT_VLAN:-}" ]] && NET_STR+=",tag=${CT_VLAN}"

  msg_info "Creating LXC container CT${CT_ID}"
  pct create "$CT_ID" "$TEMPLATE" \
    -arch amd64 -cores "$CT_CPU" -hostname "${CT_HN:-$NSAPP}" \
    -memory "$CT_RAM" -net0 "$NET_STR" -onboot 1 -ostype debian \
    -rootfs "${ROOTFS}:${CT_DISK}" -swap 512 -tags "$CT_TAGS" \
    -unprivileged 1 -features "nesting=1" >/dev/null 2>&1
  msg_ok "Container CT${CT_ID} created"

  msg_info "Starting container"
  pct start "$CT_ID" >/dev/null 2>&1; sleep 6
  msg_ok "Container started"

  msg_info "Waiting for network"
  local tries=0
  until pct exec "$CT_ID" -- ping -c1 -W2 8.8.8.8 &>/dev/null; do
    tries=$((tries+1)); [[ $tries -gt 20 ]] && msg_error "Network timeout."; sleep 2
  done
  msg_ok "Network ready"
}

# ── App installation (runs inside the container via pct exec) ─────────────────
install_app_in_container() {
  local UPDATE_MODE="${1:-}"
  pct exec "$CT_ID" -- bash -s -- "$UPDATE_MODE" << CONTAINER_SCRIPT
set -euo pipefail
UPDATE_MODE="\${1:-}"
YW='\033[33m'; GN='\033[1;92m'; CL='\033[m'; BFR="\\\\r\\\\033[K"; TAB="  "
CM="\${GN}✓\${CL}"; BFR="\\\\r\\\\033[K"
msg_info() { echo -ne "\${TAB}\${YW}[ .. ]\${CL} \${1}..."; }
msg_ok()   { echo -e  "\${BFR}\${TAB}\${CM} \${1}"; }

INSTALL_DIR="/opt/streamforge"
DATA_DIR="/var/lib/streamforge"
LOG_DIR="/var/log/streamforge"
SERVICE_USER="streamforge"

if [[ "\$UPDATE_MODE" != "--update" ]]; then
  msg_info "Updating packages"
  apt-get update -qq >/dev/null 2>&1
  apt-get install -y -qq curl wget gnupg2 ca-certificates build-essential nginx >/dev/null 2>&1
  msg_ok "Packages updated"

  msg_info "Installing Node.js 20 LTS"
  curl -fsSL https://deb.nodesource.com/setup_20.x | bash - >/dev/null 2>&1
  apt-get install -y -qq nodejs >/dev/null 2>&1
  msg_ok "Node.js \$(node -v) installed"

  msg_info "Creating service user and directories"
  id "\$SERVICE_USER" &>/dev/null || useradd -r -s /bin/false -d "\$INSTALL_DIR" "\$SERVICE_USER"
  mkdir -p "\${INSTALL_DIR}/server" "\${INSTALL_DIR}/public/css" "\${INSTALL_DIR}/public/js" \\
           "\${DATA_DIR}/epg" "\${DATA_DIR}/playlists" "\${DATA_DIR}/config" "\${DATA_DIR}/uploads" \\
           "\${LOG_DIR}"
  msg_ok "User and directories ready"
fi

msg_info "Writing application files"
CONTAINER_SCRIPT

  # Now push each file via base64 (zero quoting issues)
  msg_info "Deploying package.json"
  echo '' | pct exec "$CT_ID" -- bash -c 'base64 -d > /opt/streamforge/server/package.json'
  msg_ok "package.json written"

  msg_info "Deploying server (index.js)"
  echo '' | pct exec "$CT_ID" -- bash -c 'base64 -d > /opt/streamforge/server/index.js'
  msg_ok "index.js written"

  msg_info "Deploying frontend (index.html)"
  echo '' | pct exec "$CT_ID" -- bash -c 'base64 -d > /opt/streamforge/public/index.html'
  msg_ok "index.html written"

  msg_info "Deploying styles (main.css)"
  echo '' | pct exec "$CT_ID" -- bash -c 'base64 -d > /opt/streamforge/public/css/main.css'
  msg_ok "main.css written"

  msg_info "Deploying app logic (app.js)"
  echo '' | pct exec "$CT_ID" -- bash -c 'base64 -d > /opt/streamforge/public/js/app.js'
  msg_ok "app.js written"

  # npm install + system config
  pct exec "$CT_ID" -- bash << 'SYSSETUP'
set -euo pipefail
SERVICE_USER="streamforge"
INSTALL_DIR="/opt/streamforge"
DATA_DIR="/var/lib/streamforge"
LOG_DIR="/var/log/streamforge"

chown -R "$SERVICE_USER:$SERVICE_USER" "$INSTALL_DIR" "$DATA_DIR" "$LOG_DIR"
chmod 750 "$DATA_DIR"

echo "[sf] Installing npm dependencies..."
cd "$INSTALL_DIR/server"
sudo -u "$SERVICE_USER" npm install --production --quiet >/dev/null 2>&1
echo "[sf] npm done"

CONFIG_FILE="$DATA_DIR/config/config.json"
if [[ ! -f "$CONFIG_FILE" ]]; then
  SERVER_IP=$(hostname -I | awk '{print $1}')
  cat > "$CONFIG_FILE" << CONFJSON
{
  "port": 8080,
  "baseUrl": "http://${SERVER_IP}",
  "dataDir": "${DATA_DIR}",
  "logDir": "${LOG_DIR}",
  "epgRefreshHours": 24,
  "epgDaysAhead": 7,
  "version": "1.0.0"
}
CONFJSON
  chown "$SERVICE_USER:$SERVICE_USER" "$CONFIG_FILE"
fi

cat > /etc/systemd/system/streamforge.service << SVCEOF
[Unit]
Description=StreamForge IPTV Manager
Documentation=https://github.com/rpoltera/streamforge
After=network.target

[Service]
Type=simple
User=$SERVICE_USER
Group=$SERVICE_USER
WorkingDirectory=$INSTALL_DIR/server
ExecStart=/usr/bin/node $INSTALL_DIR/server/index.js
Restart=always
RestartSec=10
StandardOutput=append:$LOG_DIR/streamforge.log
StandardError=append:$LOG_DIR/error.log
Environment=NODE_ENV=production
Environment=SF_CONFIG=$CONFIG_FILE
Environment=SF_DATA=$DATA_DIR
Environment=SF_LOG=$LOG_DIR
NoNewPrivileges=yes
PrivateTmp=yes
ProtectSystem=strict
ReadWritePaths=$DATA_DIR $LOG_DIR
ProtectHome=yes

[Install]
WantedBy=multi-user.target
SVCEOF

cat > /etc/nginx/sites-available/streamforge << 'NGINXEOF'
server {
    listen 80 default_server;
    listen [::]:80 default_server;
    server_name _;
    client_max_body_size 500M;
    location / {
        proxy_pass         http://127.0.0.1:8080;
        proxy_http_version 1.1;
        proxy_set_header   Upgrade $http_upgrade;
        proxy_set_header   Connection 'upgrade';
        proxy_set_header   Host $host;
        proxy_set_header   X-Real-IP $remote_addr;
        proxy_read_timeout 300s;
    }
    location /stream/ {
        proxy_pass      http://127.0.0.1:8080;
        proxy_buffering off;
        proxy_read_timeout 3600s;
    }
    location ~* \.(m3u|m3u8|xml)$ {
        proxy_pass http://127.0.0.1:8080;
        add_header Cache-Control "no-store, no-cache";
        expires 0;
    }
}
NGINXEOF

ln -sf /etc/nginx/sites-available/streamforge /etc/nginx/sites-enabled/streamforge
rm -f /etc/nginx/sites-enabled/default
nginx -t >/dev/null 2>&1

cat > /etc/logrotate.d/streamforge << LOGEOF
$LOG_DIR/*.log {
    daily
    rotate 14
    compress
    delaycompress
    missingok
    notifempty
    create 0640 $SERVICE_USER $SERVICE_USER
}
LOGEOF

systemctl daemon-reload
systemctl enable streamforge nginx >/dev/null 2>&1
systemctl restart nginx
systemctl start streamforge
sleep 3
systemctl is-active --quiet streamforge && echo "[sf] StreamForge running OK" || { echo "[sf] FAILED"; journalctl -u streamforge -n 20 --no-pager; exit 1; }
SYSSETUP
}

# ── Set container description ─────────────────────────────────────────────────
set_description() {
  local ip
  ip=$(pct exec "$CT_ID" -- hostname -I 2>/dev/null | awk '{print $1}')
  pct set "$CT_ID" -description "# StreamForge IPTV Manager

- **Web UI**: http://${ip}
- **M3U**: http://${ip}/iptv.m3u
- **XMLTV EPG**: http://${ip}/xmltv.xml

[github.com/rpoltera/streamforge](https://github.com/rpoltera/streamforge)" 2>/dev/null || true
}

# ── Main ──────────────────────────────────────────────────────────────────────
main() {
  command -v pveversion &>/dev/null || { echo -e "${RD}Must run on a Proxmox VE host.${CL}"; exit 1; }
  header_info
  check_existing
  prompt_settings
  echo ""
  get_template
  create_container
  echo ""
  msg_info "Installing StreamForge into CT${CT_ID}"
  install_app_in_container
  msg_ok "StreamForge installed"
  set_description
  local ip
  ip=$(pct exec "$CT_ID" -- hostname -I 2>/dev/null | awk '{print $1}')
  echo ""
  echo -e "${GN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${CL}"
  echo -e "${GN}  StreamForge deployed successfully to CT${CT_ID}!${CL}"
  echo -e "${GN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${CL}"
  echo ""
  echo -e "  ${YW}Web UI:${CL}       ${BL}http://${ip}${CL}"
  echo -e "  ${YW}M3U playlist:${CL} ${BL}http://${ip}/iptv.m3u${CL}"
  echo -e "  ${YW}XMLTV EPG:${CL}   ${BL}http://${ip}/xmltv.xml${CL}"
  echo -e "  ${YW}API status:${CL}  ${BL}http://${ip}/api/status${CL}"
  echo ""
  echo -e "  ${DGN}Service commands (enter with: pct enter ${CT_ID})${CL}"
  echo -e "    systemctl status streamforge"
  echo -e "    journalctl -u streamforge -f"
  echo ""
}

main
